// student-form.component.ts
import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { StudentService } from '../../services/api.service';
import { HttpClient } from '@angular/common/http';

@Component({ selector: 'app-student-form', templateUrl: './student-form.component.html' })
export class StudentFormComponent implements OnInit {
  form: FormGroup;
  departments: any[] = [];
  isEdit = false; id: number | null = null;
  loading = false; saving = false; error = '';

  constructor(private fb: FormBuilder, private svc: StudentService,
    private route: ActivatedRoute, private router: Router, private http: HttpClient) {
    this.form = this.fb.group({
      first_name:      ['', Validators.required],
      last_name:       ['', Validators.required],
      email:           ['', [Validators.required, Validators.email]],
      password:        ['Student@123'],
      date_of_birth:   [''],
      gender:          ['Male'],
      phone:           [''],
      address:         [''],
      department_id:   ['', Validators.required],
      current_semester:['1'],
      enrollment_year: [new Date().getFullYear()]
    });
  }

  ngOnInit() {
    this.http.get<any>('http://localhost:3000/api/courses').subscribe(r => {
      // load departments separately
    });
    this.http.get<any>('http://localhost:3000/api/students').subscribe();
    // Load departments
    this.http.get<any>('http://localhost:3000/api/courses').subscribe();
    fetch('http://localhost:3000/api/courses', { headers: { Authorization: 'Bearer ' + localStorage.getItem('token') } })
      .then(r => r.json()).then(() => {});
    // Use inline departments for now
    this.departments = [
      { id: 1, name: 'Computer Science' },
      { id: 2, name: 'Information Technology' },
      { id: 3, name: 'Electronics' }
    ];

    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.isEdit = true; this.id = +id; this.loading = true;
      this.svc.getOne(+id).subscribe({
        next: r => { this.form.patchValue(r.data); this.loading = false; },
        error: () => this.loading = false
      });
    }
  }

  submit() {
    if (this.form.invalid) return;
    this.saving = true; this.error = '';
    const obs = this.isEdit
      ? this.svc.update(this.id!, this.form.value)
      : this.svc.create(this.form.value);
    obs.subscribe({
      next: () => this.router.navigate(['/students']),
      error: err => { this.error = err.error?.message || 'Save failed'; this.saving = false; }
    });
  }
}
